    18→// Robust JSON parser — handles malformed LLM output (markdown fences, trailing commas, unescaped chars)
    19→function safeParseJSON(text) {
    20→  if (!text || typeof text !== 'string') return null;
    21→
    22→  // Step 1: Strip markdown code fences
    23→  let cleaned = text.replace(/```(?:json)?\s*/gi, '').replace(/```\s*/g, '');
    24→
    25→  // Step 2: Extract the outermost JSON object or array
    26→  const match = cleaned.match(/(\{[\s\S]*\}|\[[\s\S]*\])/);
    27→  if (!match) return null;
    28→  cleaned = match[0];
    29→
    30→  // Step 3: Try direct parse first
    31→  try { return JSON.parse(cleaned); } catch (e) { /* continue to repair */ }
    32→
    33→  // Step 4: Remove trailing commas before } or ]
    34→  let repaired = cleaned.replace(/,\s*([}\]])/g, '$1');
    35→
    36→  // Step 5: Strip control characters (except \n \r \t) within strings
    37→  repaired = repaired.replace(/[\x00-\x08\x0B\x0C\x0E-\x1F]/g, '');
    38→
    39→  try { return JSON.parse(repaired); } catch (e) { /* continue */ }
    40→
    41→  // Step 6: Fix unescaped newlines inside JSON strings (replace literal newlines with \n)
    42→  repaired = repaired.replace(/"([^"]*?)"/g, (match, content) => {
    43→    return '"' + content.replace(/\n/g, '\\n').replace(/\r/g, '\\r').replace(/\t/g, '\\t') + '"';
    44→  });
    45→
    46→  try { return JSON.parse(repaired); } catch (e) { /* continue */ }
    47→
    48→  // Step 7: Last resort — try to fix common quote escaping issues
    49→  // Replace curly/smart quotes with straight quotes
    50→  repaired = repaired.replace(/[\u201C\u201D\u201E\u201F\u2033\u2036]/g, '"');
    51→  repaired = repaired.replace(/[\u2018\u2019\u201A\u201B\u2032\u2035]/g, "'");
    52→
    53→  try { return JSON.parse(repaired); } catch (e) {
    54→    console.warn('[safeParseJSON] All repair attempts failed:', e.message);
    55→    return null;
    56→  }
    57→}
