    59→// Upload a base64 image frame to R2 and return the CDN URL
    60→// The Polsia OpenAI proxy only supports HTTP URLs for vision, NOT base64 data URIs
    61→async function uploadFrameToR2(base64Data, index) {
    62→  try {
    63→    // Strip data URI prefix if present
    64→    const raw = base64Data.replace(/^data:image\/\w+;base64,/, '');
    65→    const buffer = Buffer.from(raw, 'base64');
    66→
    67→    const formData = new FormData();
    68→    formData.append('file', buffer, {
    69→      filename: `video-frame-${Date.now()}-${index}.jpg`,
    70→      contentType: 'image/jpeg'
    71→    });
    72→
    73→    const res = await fetch('https://polsia.com/api/proxy/r2/upload', {
    74→      method: 'POST',
    75→      headers: {
    76→        'Authorization': `Bearer ${process.env.POLSIA_API_KEY}`,
    77→        ...formData.getHeaders()
    78→      },
    79→      body: formData
    80→    });
    81→
    82→    const result = await res.json();
    83→    if (!result.success) {
    84→      console.error(`R2 frame upload failed (frame ${index}):`, result.error);
    85→      return null;
    86→    }
    87→    return result.file.url;
    88→  } catch (err) {
    89→    console.error(`R2 frame upload error (frame ${index}):`, err.message);
    90→    return null;
    91→  }
    92→}
