    96→async function chat(message, options = {}) {
    97→  // Handle both string messages and arrays of message objects
    98→  let messages;
    99→  if (Array.isArray(message)) {
   100→    // Filter out system messages and extract them
   101→    const systemMessages = message.filter(m => m.role === 'system');
   102→    const nonSystemMessages = message.filter(m => m.role !== 'system');
   103→
   104→    // Use the first system message content as the system prompt if not already set
   105→    if (systemMessages.length > 0 && !options.system) {
   106→      options.system = systemMessages[0].content;
   107→    }
   108→
   109→    // Ensure messages have proper format (content must be string or array)
   110→    messages = nonSystemMessages.map(m => ({
   111→      role: m.role,
   112→      content: typeof m.content === 'string' ? m.content : String(m.content)
   113→    }));
   114→  } else {
   115→    // Simple string message
   116→    messages = [{ role: 'user', content: String(message) }];
   117→  }
   118→
   119→  // Ensure we have at least one message
   120→  if (messages.length === 0) {
   121→    messages = [{ role: 'user', content: 'Hello' }];
   122→  }
   123→
   124→  // Use the provider service with automatic fallback
   125→  return aiProvider.chatCompletion(messages, options);
