   223→// Normalize vision analysis result — different AI models use different field names
   224→// Maps common variations to the expected field names
   225→function normalizeVisionResult(parsed) {
   226→  if (!parsed || typeof parsed !== 'object') return parsed;
   227→  const result = { ...parsed };
   228→
   229→  // Normalize field name variations
   230→  const fieldMappings = {
   231→    eye_contact: ['eye_contact', 'eyeContact', 'eye_contact_score', 'gaze'],
   232→    facial_expressions: ['facial_expressions', 'facialExpressions', 'expressions', 'facial_expression'],
   233→    body_language: ['body_language', 'bodyLanguage', 'body_language_score', 'posture'],
   234→    professional_appearance: ['professional_appearance', 'professionalAppearance', 'appearance', 'camera_setup'],
   235→    overall_presentation: ['overall_presentation', 'overallPresentation', 'overall_score', 'overall'],
   236→  };
   237→
   238→  for (const [target, alternatives] of Object.entries(fieldMappings)) {
   239→    if (!result[target]) {
   240→      for (const alt of alternatives) {
   241→        if (result[alt] !== undefined) {
   242→          result[target] = result[alt];
   243→          break;
   244→        }
   245→      }
   246→    }
   247→    // Normalize score-only values into {score, feedback} objects
   248→    if (target !== 'overall_presentation' && result[target] !== undefined) {
   249→      if (typeof result[target] === 'number') {
   250→        result[target] = { score: result[target], feedback: '' };
   251→      } else if (typeof result[target] === 'object' && result[target] !== null) {
   252→        // Ensure score is a number
   253→        if (result[target].score === undefined && result[target].rating !== undefined) {
   254→          result[target].score = result[target].rating;
   255→        }
   256→        if (typeof result[target].score !== 'number') {
   257→          result[target].score = parseInt(result[target].score) || 5;
   258→        }
   259→        result[target].feedback = result[target].feedback || result[target].assessment || result[target].comment || '';
   260→      }
   261→    }
   262→  }
   263→
   264→  // Normalize overall_presentation to a number
   265→  if (typeof result.overall_presentation === 'object' && result.overall_presentation !== null) {
   266→    result.overall_presentation = result.overall_presentation.score || result.overall_presentation.rating || 5;
   267→  }
   268→  if (typeof result.overall_presentation !== 'number') {
   269→    result.overall_presentation = parseInt(result.overall_presentation) || 5;
   270→  }
   271→
   272→  // Ensure timestamped_notes is an array
   273→  if (!Array.isArray(result.timestamped_notes)) {
   274→    result.timestamped_notes = result.timestamped_notes ? [result.timestamped_notes] : [];
   275→  }
   276→
   277→  return result;
   278→}
