   309→      keyFrames.map((frame, i) => uploadFrameToR2(frame, i))
   310→    );
   311→    const imageUrls = uploadResults.filter(url => url !== null);
   312→
   313→    if (imageUrls.length > 0) {
   314→      console.log(`[video-analysis] ${imageUrls.length}/${keyFrames.length} frames uploaded to R2. Calling vision API...`);
   315→
   316→      const visionPrompt = `You are an expert interview presentation coach. Analyze these ${imageUrls.length} video frames captured during an interview practice recording.
   317→
   318→**Interview Question:** "${question}"
   319→**Response Duration:** ${durationSeconds} seconds
   320→**Transcription excerpt:** "${transcription.substring(0, 500)}"
   321→
   322→Look at the ACTUAL video frames and analyze:
   323→1. **Eye Contact** — Is the candidate looking at the camera? Looking away? Consistent or sporadic?
   324→2. **Facial Expressions** — Are they engaged, confident, nervous? Smiling appropriately? Tense jaw/brow?
   325→3. **Body Language** — Posture (leaning in/slouching), hand gestures (natural/fidgeting/stiff), shoulder position
   326→4. **Professional Appearance** — Camera framing, lighting, background, clothing visibility, camera angle
   327→
   328→Be SPECIFIC about what you SEE in the frames. Reference actual visual details — don't guess from speech patterns.
   329→
   330→Return a JSON object with this EXACT structure:
   331→{
   332→  "eye_contact": { "score": 1-10, "feedback": "specific feedback based on what you SEE in the frames" },
   333→  "facial_expressions": { "score": 1-10, "feedback": "specific feedback about visible facial expressions" },
   334→  "body_language": { "score": 1-10, "feedback": "specific feedback about visible posture, gestures" },
   335→  "professional_appearance": { "score": 1-10, "feedback": "feedback about camera setup, lighting, background you can SEE" },
   336→  "overall_presentation": 1-10,
   337→  "summary": "2-3 sentence overall visual presentation assessment referencing what you observed",
   338→  "timestamped_notes": [
   339→    { "frame": 1, "note": "what you observe in the opening frame" },
   340→    { "frame": ${Math.max(1, Math.ceil(imageUrls.length / 2))}, "note": "what you observe in the middle frame" },
