   383→  const words = transcription.trim().split(/\s+/).filter(w => w.length > 0);
   384→  const wordCount = words.length;
   385→  const wpm = durationSeconds > 0 ? Math.round((wordCount / durationSeconds) * 60) : 0;
   386→
   387→  const fillerList = ['um', 'uh', 'like', 'you know', 'so', 'basically', 'actually', 'literally', 'right', 'i mean'];
