   420→  "facial_expressions": { "score": 1-10, "feedback": "specific feedback about facial engagement, confidence signals" },
   421→  "body_language": { "score": 1-10, "feedback": "specific feedback about posture, gestures, and physical presence" },
   422→  "professional_appearance": { "score": 1-10, "feedback": "tips about camera setup, lighting, background for video interviews" },
   423→  "overall_presentation": 1-10,
   424→  "summary": "2-3 sentence overall presentation assessment with key improvement area",
   425→  "timestamped_notes": [
   426→    { "frame": 1, "note": "coaching tip for the opening of the response" },
   427→    { "frame": ${Math.max(1, Math.floor(frameCount / 2))}, "note": "coaching tip for the middle section" },
   428→    { "frame": ${frameCount}, "note": "coaching tip for the closing" }
   429→  ]
   430→}
   431→
   432→Only return the JSON object, no other text.`;
   433→
   434→  try {
   435→    console.log(`[video-analysis] Using text-based LLM fallback for presentation coaching (${frameCount} frames, ${wpm} WPM, ${totalFillers} fillers)`);
   436→
   437→    const result = await aiProvider.chatCompletion([
   438→      { role: 'system', content: 'You are an expert interview coach specializing in non-verbal communication, body language, and video interview presentation. Provide specific, actionable coaching. Always return valid JSON.' },
   439→      { role: 'user', content: textPrompt }
   440→    ], {
   441→      module: 'quick_practice',
   442→      feature: 'video_presentation',
   443→      response_format: { type: 'json_object' },
   444→      maxTokens: 1024,
   445→      task: 'interview-coaching',
   446→    });
   447→
   448→    console.log('[video-analysis] Text-based presentation coaching received successfully (fallback)');
   449→    const parsed = safeParseJSON(result);
   450→    if (parsed && typeof parsed === 'object') {
   451→      const normalized = normalizeVisionResult(parsed);
   452→      if (normalized.eye_contact && normalized.body_language) return normalized;
   453→      console.warn('[video-analysis] Text fallback missing expected fields after normalization. Keys:', Object.keys(parsed).join(', '));
   454→    } else {
   455→      console.warn('[video-analysis] Text fallback could not be parsed');
   456→    }
