   464→// Select evenly-spaced key frames from a larger set
   465→function selectKeyFrames(frames, count) {
   466→  const result = [];
   467→  const step = (frames.length - 1) / (count - 1);
   468→  for (let i = 0; i < count; i++) {
   469→    result.push(frames[Math.round(i * step)]);
   470→  }
   471→  return result;
   472→}
