   474→// Analyze speech transcription for communication quality
   475→function analyzeSpeechPatterns(transcription, durationSeconds) {
   476→  const words = transcription.trim().split(/\s+/).filter(w => w.length > 0);
   477→  const wordCount = words.length;
   478→  const wpm = durationSeconds > 0 ? Math.round((wordCount / durationSeconds) * 60) : 0;
   479→
   480→  // Filler word detection
   481→  const fillerWords = ['um', 'uh', 'like', 'you know', 'so', 'basically', 'actually', 'literally', 'right', 'okay so', 'i mean'];
   482→  const fillerCounts = {};
   483→  let totalFillers = 0;
   484→  const lowerTranscription = transcription.toLowerCase();
   485→
   486→  for (const filler of fillerWords) {
   487→    const regex = new RegExp(`\\b${filler}\\b`, 'gi');
   488→    const matches = lowerTranscription.match(regex);
   489→    if (matches && matches.length > 0) {
   490→      fillerCounts[filler] = matches.length;
   491→      totalFillers += matches.length;
   492→    }
   493→  }
   494→
   495→  const fillerRate = wordCount > 0 ? (totalFillers / wordCount) * 100 : 0;
   496→
   497→  // Pace analysis
   498→  let paceAssessment = 'good';
   499→  let paceFeedback = '';
   500→  if (wpm < 100) {
   501→    paceAssessment = 'too_slow';
   502→    paceFeedback = 'Your speaking pace is quite slow. Try to speak more naturally and with more energy. Aim for 120-150 words per minute.';
   503→  } else if (wpm < 120) {
   504→    paceAssessment = 'slightly_slow';
   505→    paceFeedback = 'Your pace is a bit slow. Try to increase your speaking speed slightly for more engaging delivery.';
   506→  } else if (wpm <= 160) {
   507→    paceAssessment = 'good';
   508→    paceFeedback = 'Your speaking pace is natural and easy to follow. Well done!';
   509→  } else if (wpm <= 180) {
   510→    paceAssessment = 'slightly_fast';
   511→    paceFeedback = 'You\'re speaking a bit quickly. Try to slow down slightly and pause between key points.';
   512→  } else {
   513→    paceAssessment = 'too_fast';
   514→    paceFeedback = 'You\'re speaking too fast — this can signal nervousness. Take deliberate pauses between sentences and breathe.';
   515→  }
   516→
   517→  // Sentence structure analysis
   518→  const sentences = transcription.split(/[.!?]+/).filter(s => s.trim().length > 0);
   519→  const avgSentenceLength = sentences.length > 0 ? Math.round(wordCount / sentences.length) : 0;
   520→
   521→  // Communication score (1-10)
   522→  let communicationScore = 7;
   523→  // Penalize for filler words
   524→  if (fillerRate > 5) communicationScore -= 2;
   525→  else if (fillerRate > 3) communicationScore -= 1;
   526→  // Penalize for bad pace
   527→  if (paceAssessment === 'too_slow' || paceAssessment === 'too_fast') communicationScore -= 1.5;
   528→  else if (paceAssessment === 'slightly_slow' || paceAssessment === 'slightly_fast') communicationScore -= 0.5;
   529→  // Reward for good sentence structure
   530→  if (avgSentenceLength >= 10 && avgSentenceLength <= 25) communicationScore += 0.5;
   531→  // Penalize for very short responses
   532→  if (wordCount < 50) communicationScore -= 2;
   533→  else if (wordCount < 100) communicationScore -= 1;
   534→  // Reward for substantial responses
   535→  if (wordCount >= 150 && wordCount <= 400) communicationScore += 0.5;
   536→
   537→  communicationScore = Math.max(1, Math.min(10, Math.round(communicationScore * 10) / 10));
   538→
   539→  return {
   540→    word_count: wordCount,
   541→    duration_seconds: durationSeconds,
   542→    words_per_minute: wpm,
   543→    filler_words: fillerCounts,
   544→    total_fillers: totalFillers,
   545→    filler_rate: Math.round(fillerRate * 10) / 10,
   546→    pace: {
   547→      assessment: paceAssessment,
   548→      wpm,
   549→      feedback: paceFeedback
   550→    },
   551→    sentence_count: sentences.length,
   552→    avg_sentence_length: avgSentenceLength,
   553→    communication_score: communicationScore,
   554→    tips: generateSpeechTips(fillerRate, wpm, wordCount, totalFillers, fillerCounts)
   555→  };
   556→}
   557→
   558→function generateSpeechTips(fillerRate, wpm, wordCount, totalFillers, fillerCounts) {
   559→  const tips = [];
   560→
   561→  if (fillerRate > 3) {
   562→    const topFillers = Object.entries(fillerCounts)
   563→      .sort((a, b) => b[1] - a[1])
   564→      .slice(0, 3)
   565→      .map(([word, count]) => `"${word}" (${count}x)`);
   566→    tips.push(`Reduce filler words — you used ${totalFillers} fillers: ${topFillers.join(', ')}. Try pausing silently instead.`);
   567→  }
   568→
   569→  if (wpm > 160) {
   570→    tips.push('Slow down your pace. Take a breath between key points to let your message land.');
   571→  } else if (wpm < 110) {
   572→    tips.push('Pick up the pace slightly. A faster tempo projects confidence and engagement.');
   573→  }
   574→
   575→  if (wordCount < 80) {
   576→    tips.push('Your response was quite short. Aim for 1-2 minutes of speaking time to give a comprehensive answer.');
   577→  }
   578→
   579→  if (tips.length === 0) {
   580→    tips.push('Strong verbal delivery! Your pace and clarity are good. Keep practicing to maintain consistency.');
   581→  }
   582→
   583→  return tips;
   584→}
