   620→
   621→TRANSCRIPTION:
   622→"${transcription.substring(0, 3000)}"
   623→
   624→METRICS:
   625→- Duration: ${durationSeconds} seconds
   626→- Word count: ${words.length}
   627→- Speaking pace: ${wpm} words per minute
   628→
   629→Score each vocal dimension 1-10 based on transcription patterns, language choice, and speech structure:
   630→
   631→1. Voice Confidence: hedging vs decisive language, qualifiers, weak/strong openers
   632→2. Vocal Variety: sentence length variation, rhetorical devices, tonal shifts from punctuation
   633→3. Pacing & Rhythm: natural pauses, run-on sentences, breath points
   634→4. Articulation: word choice clarity, specificity vs vagueness
   635→5. Energy & Enthusiasm: active voice, strong verbs, passion indicators
   636→
   637→Return JSON with this structure:
   638→{
   639→  "voice_confidence": { "score": <1-10>, "feedback": "<one sentence>" },
   640→  "vocal_variety": { "score": <1-10>, "feedback": "<one sentence>" },
   641→  "pacing_rhythm": { "score": <1-10>, "feedback": "<one sentence>" },
   642→  "articulation": { "score": <1-10>, "feedback": "<one sentence>" },
   643→  "energy": { "score": <1-10>, "feedback": "<one sentence>" },
   644→  "overall_voice_score": <1-10>,
   645→  "voice_summary": "<2-3 sentences>",
   646→  "voice_tips": ["<tip 1>", "<tip 2>", "<tip 3>"]
   647→}`;
   648→
   649→    // Use OpenAI directly — single reliable provider with forced JSON output.
   650→    // The 3-provider race (anthropic, openai, nim_ultra) fired simultaneously and
   651→    // the fastest (often NIM) returned content safeParseJSON couldn't handle.
   652→    const params = {
   653→      model: 'gpt-4o-mini',
   654→      messages: [
   655→        { role: 'system', content: 'You are an expert interview coach specializing in vocal delivery analysis. Return only valid JSON.' },
   656→        { role: 'user', content: prompt }
   657→      ],
   658→      response_format: { type: 'json_object' },
   659→      max_tokens: 1024,
   660→      temperature: 0.7,
   661→    };
   662→    params.task = 'voice-analysis';
   663→
   664→    // 12s timeout — fits within the 18s per-promise budget from analyzeVideoInterviewResponse
   665→    const response = await Promise.race([
   666→      openai.chat.completions.create(params),
   667→      new Promise((_, reject) => setTimeout(() => reject(new Error('Voice analysis timeout (12s)')), 12000))
   668→    ]);
   669→
   670→    const text = response.choices[0]?.message?.content;
   671→    if (!text) {
   672→      console.warn('[voice-quality] OpenAI returned empty content');
   673→      return null;
   674→    }
   675→
   676→    const parsed = safeParseJSON(text);
   677→    if (parsed) {
   678→      for (const key of ['voice_confidence', 'vocal_variety', 'pacing_rhythm', 'articulation', 'energy']) {
   679→        if (parsed[key]?.score != null) parsed[key].score = Math.max(1, Math.min(10, parsed[key].score));
   680→      }
   681→      if (parsed.overall_voice_score != null) parsed.overall_voice_score = Math.max(1, Math.min(10, parsed.overall_voice_score));
   682→      console.log('[voice-quality] ✅ Real voice analysis complete (OpenAI gpt-4o-mini)');
   683→      return parsed;
   684→    }
   685→
   686→    console.warn('[voice-quality] Failed to parse response. First 300 chars:', text.substring(0, 300));
   687→    return null;
   688→  } catch (err) {
   689→    console.error('[voice-quality] Error:', err.message || err);
   690→    return null;
   691→  }
   692→}
