   695→async function analyzeVideoInterviewResponse(question, transcription, frames, durationSeconds, keyPoints, options = {}) {
   696→  const audioData = options.audioData || null;
   697→  let finalTranscription = transcription;
   698→
   699→  // Step 1: If audio data available, try Whisper for more accurate transcription
   700→  // FIX (Feb 15, 2026): Cap Whisper at 5s — ASR cascade can take 20s, eating into
   701→  // the analysis time budget and causing frontend timeout (35s). Browser transcription
   702→  // is good enough as fallback.
   703→  let whisperResult = null;
   704→  if (audioData) {
   705→    try {
   706→      console.log('[ai] Transcribing audio with Whisper (5s cap)...');
   707→      whisperResult = await Promise.race([
   708→        transcribeAudioWithWhisper(audioData, options),
   709→        new Promise((resolve) => setTimeout(() => {
   710→          console.warn('[ai] Whisper 5s cap hit — using browser transcription');
   711→          resolve(null);
   712→        }, 5000))
   713→      ]);
   714→      if (whisperResult && whisperResult.text && whisperResult.text.trim().length > 20) {
   715→        finalTranscription = whisperResult.text;
   716→        console.log(`[ai] Whisper transcription: ${finalTranscription.length} chars (replaced browser transcription)`);
   717→      } else {
   718→        console.log('[ai] Whisper result too short or timed out, keeping browser transcription');
   719→      }
   720→    } catch (err) {
   721→      console.warn('[ai] Whisper failed, using browser transcription:', err.message);
   722→    }
   723→  }
   724→
   725→  // Step 2: Run all analyses in parallel with PER-PROMISE timeouts + MASTER timeout
   726→  // BUG FIX (Feb 15, 2026 — Task #32681): Promise.allSettled was hanging forever when provider
   727→  // API calls never settled (HTTP response streaming but never completing). With 4 parallel calls
   728→  // each racing 3 providers (12 concurrent API requests from #32666), some providers become
   729→  // unresponsive. Fix: (1) Lower per-promise timeout to 18s, (2) Add a 25s master timeout on
   730→  // Promise.allSettled that force-resolves with partial results if any promise hangs.
   731→  const PER_PROMISE_TIMEOUT_MS = 18000;
   732→  const MASTER_TIMEOUT_MS = 25000;
   733→
   734→  function withTimeout(promise, ms, label) {
   735→    return new Promise((resolve, reject) => {
   736→      const timer = setTimeout(() => {
   737→        console.warn(`[video-analysis] ${label} timed out after ${ms}ms`);
   738→        reject(new Error(`${label} timeout after ${ms}ms`));
   739→      }, ms);
   740→      promise.then(
   741→        val => { clearTimeout(timer); resolve(val); },
   742→        err => { clearTimeout(timer); reject(err); }
   743→      );
   744→    });
   745→  }
   746→
   747→  // FIX (Feb 15, 2026): Pass transcription context to video presentation analysis
   748→  // so the text-based LLM can generate personalized coaching from speech patterns
   749→  const presentationOptions = {
   750→    ...options,
   751→    transcription: finalTranscription,
   752→    durationSeconds,
   753→    question,
   754→  };
   755→
   756→  const analysisPromises = [
   757→    withTimeout(analyzeInterviewResponse(question, finalTranscription, keyPoints, options), PER_PROMISE_TIMEOUT_MS, 'contentAnalysis'),
   758→    withTimeout(generateInterviewCoaching(question, finalTranscription, { score: 5, strengths: [], improvements: [] }, options), PER_PROMISE_TIMEOUT_MS, 'contentCoaching'),
   759→    withTimeout(analyzeVideoPresentation(frames, presentationOptions), PER_PROMISE_TIMEOUT_MS, 'videoPresentation'),
   760→    // FIX (Feb 15, 2026 — Task #32666): ALWAYS run voice quality analysis.
   761→    // analyzeVoiceQuality() only analyzes transcription TEXT (not audio) — gating it behind
   762→    // audioData was wrong because it skipped voice analysis entirely when MediaRecorder failed
   763→    // (common on iOS). This caused the Voice & Tone Analysis section to disappear from the UI.
   764→    withTimeout(analyzeVoiceQuality(finalTranscription, durationSeconds, options), PER_PROMISE_TIMEOUT_MS, 'voiceAnalysis')
   765→  ];
   766→
   767→  // FIX (Feb 15, 2026 — Task #32681): Track settlements individually so master timeout
   768→  // can force-resolve with partial results instead of hanging forever.
   769→  const partialResults = new Array(analysisPromises.length).fill(null);
   770→  analysisPromises.forEach((p, i) => {
   771→    p.then(
   772→      val => { partialResults[i] = { status: 'fulfilled', value: val }; },
   773→      err => { partialResults[i] = { status: 'rejected', reason: err }; }
   774→    );
   775→  });
   776→
   777→  let settled;
   778→  try {
   779→    settled = await Promise.race([
   780→      Promise.allSettled(analysisPromises),
