   782→        const settledCount = partialResults.filter(r => r !== null).length;
   783→        console.warn(`[video-analysis] ⏱️ Master timeout (${MASTER_TIMEOUT_MS}ms) — ${settledCount}/${partialResults.length} settled, forcing response`);
   784→        // Use whatever has settled so far; fill unsettled with rejections
   785→        resolve(partialResults.map(r => r || { status: 'rejected', reason: new Error('Master timeout — analysis took too long') }));
   786→      }, MASTER_TIMEOUT_MS))
   787→    ]);
   788→  } catch (err) {
