   790→    settled = partialResults.map(r => r || { status: 'rejected', reason: err });
   791→  }
   792→
   793→  // Extract results with fallbacks for any failed analyses
   794→  // BUG FIX: Use helper function with multiple safety layers to prevent null crashes.
   795→  // Previous null checks still let through edge cases where AI returned non-null truthy values
