   338→// ─── GET /practice/stats ────────────────────────────────────────
   339→router.get('/practice/stats', authMiddleware, async (req, res) => {
   340→  try {
   341→    const stats = await pool.query(
   342→      `SELECT
   343→        COUNT(*) as total_questions,
   344→        AVG(score) as average_score,
   345→        MAX(created_at) as last_practice
   346→       FROM practice_sessions
   347→       WHERE user_id = $1`,
   348→      [req.user.id]
   349→    );
   350→
   351→    const improvement = await pool.query(
   352→      `WITH ordered_sessions AS (
   353→        SELECT score, ROW_NUMBER() OVER (ORDER BY created_at) as rn,
   354→               COUNT(*) OVER () as total
   355→        FROM practice_sessions
   356→        WHERE user_id = $1
   357→      )
   358→      SELECT
   359→        AVG(CASE WHEN rn <= total/2 THEN score END) as first_half_avg,
   360→        AVG(CASE WHEN rn > total/2 THEN score END) as second_half_avg
   361→      FROM ordered_sessions`,
   362→      [req.user.id]
   363→    );
   364→
   365→    let improvementPercent = null;
   366→    if (improvement.rows[0].first_half_avg && improvement.rows[0].second_half_avg) {
   367→      const firstHalf = parseFloat(improvement.rows[0].first_half_avg);
   368→      const secondHalf = parseFloat(improvement.rows[0].second_half_avg);
   369→      improvementPercent = ((secondHalf - firstHalf) / firstHalf) * 100;
   370→    }
   371→
   372→    const streakResult = await pool.query(
   373→      `WITH RECURSIVE date_series AS (
   374→        SELECT CURRENT_DATE::date as check_date, 0 as days_back
   375→        UNION ALL
   376→        SELECT (check_date - INTERVAL '1 day')::date, days_back + 1
   377→        FROM date_series
   378→        WHERE days_back < 30
   379→      )
   380→      SELECT COUNT(*) as streak
   381→      FROM date_series d
   382→      WHERE EXISTS (
   383→        SELECT 1 FROM practice_sessions
   384→        WHERE user_id = $1 AND DATE(created_at) = d.check_date
   385→      )
   386→      AND d.check_date <= CURRENT_DATE
   387→      AND NOT EXISTS (
   388→        SELECT 1 FROM date_series d2
   389→        WHERE d2.check_date > d.check_date
   390→        AND d2.check_date <= CURRENT_DATE
   391→        AND NOT EXISTS (
   392→          SELECT 1 FROM practice_sessions
   393→          WHERE user_id = $1 AND DATE(created_at) = d2.check_date
   394→        )
   395→      )`,
   396→      [req.user.id]
   397→    );
   398→
   399→    res.json({
   400→      success: true,
   401→      stats: {
   402→        total_questions: parseInt(stats.rows[0].total_questions) || 0,
   403→        average_score: parseFloat(stats.rows[0].average_score) || null,
   404→        improvement: improvementPercent,
   405→        day_streak: parseInt(streakResult.rows[0].streak) || 0,
   406→        last_practice: stats.rows[0].last_practice
   407→      }
   408→    });
   409→  } catch (err) {
   410→    console.error('[QP] Get practice stats error:', err);
   411→    res.status(500).json({ error: 'Failed to fetch statistics' });
   412→  }
   413→});
